Here's how to handle each scenario with modern MSTest (3.9+):

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public sealed class MyTests
{
    private readonly TestContext _testContext;
    private string? _tempFile;

    public MyTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // 1. Windows-only: skip on other OSes
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsExpectedValue()
    {
        // Only runs on Windows; auto-skipped elsewhere
    }

    // 2. Skip in CI: local-only test
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void GpuRendering_ProducesCorrectOutput()
    {
        // Skipped when running in CI environments
    }

    // 3. Flaky external API: retry up to 3 times
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task WeatherApi_ReturnsForecast()
    {
        var result = await _httpClient.GetAsync(
            "https://api.weather.example/forecast",
            _testContext.CancellationToken);
        Assert.IsNotNull(result);
    }

    // 4. Temp files: TestCleanup runs even on failure
    [TestMethod]
    public void Export_CreatesValidFile()
    {
        _tempFile = Path.GetTempFileName();
        File.WriteAllText(_tempFile, "data");

        Assert.IsTrue(File.Exists(_tempFile));
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (_tempFile is not null && File.Exists(_tempFile))
        {
            File.Delete(_tempFile);
        }
    }
}
```

**Key points:**

| Scenario | Attribute/Pattern | Min Version |
|---|---|---|
| Windows-only | `[OSCondition(OperatingSystems.Windows)]` | 3.10+ |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` | 3.10+ |
| Flaky retries | `[Retry(3)]` | 3.9+ |
| Cleanup on failure | `[TestCleanup]` method | Any |

- **`[TestCleanup]`** always runs after each test (pass or fail), making it ideal for temp file deletion.
- **`[Retry]`** should only be used for genuinely flaky external dependencies — not to mask race conditions or shared-state bugs.
- Pair `[Timeout]` with `TestContext.CancellationToken` so the async call is cancelled cleanly when time expires.
